CREATE TABLE "build_favorites" ("user_id" uuid NOT NULL REFERENCES "users"("id") ON DELETE cascade, "build_profile_id" uuid NOT NULL REFERENCES "build_profiles"("id") ON DELETE cascade, "created_at" timestamp with time zone DEFAULT now() NOT NULL, PRIMARY KEY ("user_id", "build_profile_id"));
CREATE TABLE "party_profiles" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL, "user_id" uuid NOT NULL REFERENCES "users"("id") ON DELETE cascade, "name" varchar(80) NOT NULL, "member_build_ids" jsonb NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
